// ============================================================================
// Normaliza el payload del formulario (acepta variantes ES/EN de nombre de
// campo), valida los datos obligatorios, genera un Lead ID determinista
// (hash del email -> estable entre reenvíos del mismo lead) y construye el
// prompt de análisis para Gemini. Registra logs estructurados de cada
// intento, válido o inválido, para trazabilidad.
// ============================================================================
try {
  const body = $json.body ?? $json;

  const pick = (...keys) => {
    for (const key of keys) {
      const value = body[key];
      if (typeof value === 'string' && value.trim()) return value.trim();
    }
    return '';
  };

  const lead = {
    nombre: pick('nombre', 'name', 'fullName', 'full_name'),
    empresa: pick('empresa', 'company', 'organizacion'),
    email: pick('email', 'correo', 'mail').toLowerCase(),
    telefono: pick('telefono', 'phone', 'tel', 'movil'),
    mensaje: pick('mensaje', 'message', 'comentarios', 'comments'),
    servicioInteres: pick('servicio_interes', 'service', 'servicio', 'interest'),
    origen: pick('origen', 'source', 'utm_source') || 'formulario_web',
  };

  const errors = [];
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  if (!lead.nombre) errors.push('El campo "nombre" es obligatorio.');
  if (!lead.email || !emailRegex.test(lead.email)) errors.push('El campo "email" no es válido.');
  if (!lead.mensaje || lead.mensaje.length < 10) errors.push('El campo "mensaje" debe tener al menos 10 caracteres.');

  // Secreto compartido opcional: si se configura la variable de n8n
  // WEBHOOK_SECRET (Settings -> Variables), el formulario debe enviar la
  // cabecera x-webhook-secret con ese valor.
  const webhookSecret = $vars.WEBHOOK_SECRET;
  if (webhookSecret) {
    const receivedSecret = $json.headers?.['x-webhook-secret'];
    if (receivedSecret !== webhookSecret) errors.push('Token de autenticación inválido.');
  }

  if (errors.length > 0) {
    console.warn(JSON.stringify({
      evento: 'lead_invalido', errores: errors, email: lead.email || null,
      timestamp: new Date().toISOString(),
    }));
    return [{ json: { valid: false, statusCode: 400, errors } }];
  }

  // Lead ID determinista a partir del email: la misma persona reenviando el
  // formulario siempre produce el mismo Lead ID, coherente con el upsert
  // por email en Airtable (elimina duplicados en origen).
  const hashEmail = (str) => {
    let hash = 0;
    for (let i = 0; i < str.length; i++) hash = (hash * 31 + str.charCodeAt(i)) >>> 0;
    return hash.toString(36);
  };
  lead.leadId = `lead_${hashEmail(lead.email)}`;
  lead.receivedAt = new Date().toISOString();

  // Catálogo de servicios configurable por cliente vía variable de n8n
  // (Settings -> Variables), para poder reutilizar este mismo workflow al
  // vender la plantilla a otros clientes sin tocar el prompt.
  const servicesCatalog = $vars.SERVICES_CATALOG
    || 'automatización de procesos con IA, agentes de IA a medida, chatbots y asistentes virtuales, integración de sistemas (CRM/ERP) y consultoría de transformación digital con IA';

  const geminiPrompt = `Eres el analista comercial senior de D-Code Partners, una consultora especializada en automatización e inteligencia artificial para empresas. Analiza el siguiente lead recién recibido desde el formulario web y devuelve una evaluación objetiva y accionable para el equipo comercial.

Criterios a evaluar:
- Calidad y completitud de la información proporcionada (datos de contacto válidos, contexto claro, detalle real del mensaje).
- Señales de intención de compra explícitas o implícitas (urgencia expresada, presupuesto, plazos, dolor de negocio concreto).
- Encaje del lead con el catálogo de servicios: ${servicesCatalog}.
- Nivel de urgencia percibido (¿necesita una solución ya, a corto plazo, o está explorando opciones?).

Datos del lead:
- Nombre: ${lead.nombre}
- Empresa: ${lead.empresa || 'No especificada'}
- Email: ${lead.email}
- Teléfono: ${lead.telefono || 'No especificado'}
- Servicio de interés indicado: ${lead.servicioInteres || 'No especificado'}
- Mensaje del lead: "${lead.mensaje}"
- Origen del formulario: ${lead.origen}
- Fecha de recepción: ${lead.receivedAt}

Criterios de puntuación:
- score_ia (0-100): 0-30 lead frío/poco cualificado, 31-60 lead tibio con potencial, 61-100 lead caliente con alta intención de compra.
- prioridad: "Alta" si score_ia >= 75 o hay urgencia explícita; "Media" si score_ia está entre 45 y 74; "Baja" si score_ia < 45.
- probabilidad_compra (0-100): probabilidad estimada de conversión a cliente en los próximos 30 días.
- urgencia: "Alta", "Media" o "Baja" según el lenguaje y contexto del mensaje.
- servicio_recomendado: el servicio del catálogo que mejor resuelve la necesidad expresada.
- resumen_comercial: 2-3 frases con el diagnóstico del lead para el equipo comercial, sin repetir literalmente su mensaje.
- siguiente_accion: acción concreta y específica que debe tomar el equipo comercial en las próximas 24-48h (nunca genérica como "contactar al cliente").

Sé objetivo, básate solo en la información proporcionada y no inventes datos que no estén presentes.`;

  console.log(JSON.stringify({
    evento: 'lead_recibido', leadId: lead.leadId, email: lead.email,
    origen: lead.origen, timestamp: lead.receivedAt,
  }));

  return [{ json: { valid: true, lead, geminiPrompt } }];
} catch (err) {
  console.error(JSON.stringify({
    evento: 'error_normalizacion', mensaje: err.message,
    timestamp: new Date().toISOString(),
  }));
  return [{ json: { valid: false, statusCode: 500, errors: ['Error interno al procesar el lead.'] } }];
}

