// ============================================================================
// Extrae y valida el análisis estructurado devuelto por Gemini. Si la
// llamada a Gemini falló, devolvió un JSON incompleto, o el upsert previo
// en Airtable falló, aplica valores de reserva y registra el incidente:
// el lead nunca se queda sin score ni sin seguimiento comercial.
// ============================================================================
const httpResponse = $json;
const lead = $('Normalizar y Validar Lead').item.json.lead;
const airtableNode = $('Airtable - Crear o Actualizar Lead').item.json;
const airtableRecordId = airtableNode?.id || null;
const crmError = !airtableRecordId;

const FALLBACK = {
  score_ia: 50,
  prioridad: 'Media',
  probabilidad_compra: 50,
  urgencia: 'Media',
  servicio_recomendado: lead.servicioInteres || 'Por determinar',
  resumen_comercial: 'No se pudo generar el análisis automático de este lead. Requiere revisión manual del equipo comercial.',
  siguiente_accion: 'Revisar el lead manualmente y contactar en menos de 24h.',
};

function parseAnalysis() {
  if (httpResponse.error) return null;
  const text = httpResponse.candidates?.[0]?.content?.parts?.[0]?.text;
  if (!text) return null;
  try {
    return JSON.parse(text);
  } catch {
    return null;
  }
}

const parsed = parseAnalysis();
const aiError = !parsed;
const analysis = parsed || FALLBACK;

const clamp = (value, fallback) => {
  const n = Number(value);
  return Number.isFinite(n) ? Math.max(0, Math.min(100, Math.round(n))) : fallback;
};
const validLevel = (value, fallback) => (['Alta', 'Media', 'Baja'].includes(value) ? value : fallback);

if (aiError) {
  console.error(JSON.stringify({
    evento: 'error_analisis_ia', leadId: lead.leadId,
    motivo: httpResponse.error || 'respuesta_invalida_o_vacia',
    timestamp: new Date().toISOString(),
  }));
}
if (crmError) {
  console.error(JSON.stringify({
    evento: 'error_crm_upsert', leadId: lead.leadId,
    motivo: airtableNode?.error || 'sin_id_de_registro',
    timestamp: new Date().toISOString(),
  }));
}

const result = {
  airtableRecordId,
  crmError,
  lead,
  scoreIA: clamp(analysis.score_ia, FALLBACK.score_ia),
  prioridad: validLevel(analysis.prioridad, FALLBACK.prioridad),
  probabilidadCompra: clamp(analysis.probabilidad_compra, FALLBACK.probabilidad_compra),
  urgencia: validLevel(analysis.urgencia, FALLBACK.urgencia),
  servicioRecomendado: analysis.servicio_recomendado || FALLBACK.servicio_recomendado,
  resumenComercial: analysis.resumen_comercial || FALLBACK.resumen_comercial,
  siguienteAccion: analysis.siguiente_accion || FALLBACK.siguiente_accion,
  aiError,
};

console.log(JSON.stringify({
  evento: 'lead_analizado', leadId: lead.leadId, scoreIA: result.scoreIA,
  prioridad: result.prioridad, aiError, crmError, timestamp: new Date().toISOString(),
}));

return [{ json: result }];
